using Microsoft.VisualStudio.TestTools.UnitTesting;
using Payments;

namespace Payments.Tests;

[TestClass]
public sealed class ChargeAsyncTests
{
    private PaymentGateway _gateway = null!;

    [TestInitialize]
    public void Setup() => _gateway = new PaymentGateway();

    [TestMethod]
    public async Task ValidCharge_ReturnsSuccessWithChargeId()
    {
        var result = await _gateway.ChargeAsync("tok_valid_visa", 49.99m);

        Assert.IsTrue(result.Success);
        Assert.IsFalse(string.IsNullOrEmpty(result.ChargeId));
    }

    [TestMethod]
    public async Task MinimumAmount_Succeeds()
    {
        var result = await _gateway.ChargeAsync("tok_valid_visa", 0.01m);

        Assert.IsTrue(result.Success);
    }

    [TestMethod]
    public async Task LargeAmount_Succeeds()
    {
        var result = await _gateway.ChargeAsync("tok_valid_visa", 999_999.99m);

        Assert.IsTrue(result.Success);
    }

    [TestMethod]
    public async Task ZeroAmount_Fails()
    {
        var result = await _gateway.ChargeAsync("tok_valid_visa", 0m);

        Assert.IsFalse(result.Success);
    }

    [TestMethod]
    public async Task NegativeAmount_Fails()
    {
        var result = await _gateway.ChargeAsync("tok_valid_visa", -10m);

        Assert.IsFalse(result.Success);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentNullException))]
    public async Task NullCardToken_Throws()
    {
        await _gateway.ChargeAsync(null!, 10m);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public async Task EmptyCardToken_Throws()
    {
        await _gateway.ChargeAsync("", 10m);
    }

    [TestMethod]
    public async Task DeclinedCard_ReturnsFailure()
    {
        var result = await _gateway.ChargeAsync("tok_declined", 25.00m);

        Assert.IsFalse(result.Success);
    }

    [TestMethod]
    public async Task MultipleCharges_ReturnUniqueIds()
    {
        var r1 = await _gateway.ChargeAsync("tok_valid_visa", 10m);
        var r2 = await _gateway.ChargeAsync("tok_valid_visa", 20m);

        Assert.AreNotEqual(r1.ChargeId, r2.ChargeId);
    }
}

[TestClass]
public sealed class RefundAsyncTests
{
    private PaymentGateway _gateway = null!;

    [TestInitialize]
    public void Setup() => _gateway = new PaymentGateway();

    [TestMethod]
    public async Task ValidChargeId_ReturnsSuccessWithRefundId()
    {
        var result = await _gateway.RefundAsync("ch_valid_123");

        Assert.IsTrue(result.Success);
        Assert.IsFalse(string.IsNullOrEmpty(result.RefundId));
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentNullException))]
    public async Task NullChargeId_Throws()
    {
        await _gateway.RefundAsync(null!);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public async Task EmptyChargeId_Throws()
    {
        await _gateway.RefundAsync("");
    }

    [TestMethod]
    public async Task NonexistentChargeId_ReturnsFailure()
    {
        var result = await _gateway.RefundAsync("ch_does_not_exist");

        Assert.IsFalse(result.Success);
    }

    [TestMethod]
    public async Task RefundAfterCharge_Succeeds()
    {
        var charge = await _gateway.ChargeAsync("tok_valid_visa", 50m);
        Assert.IsTrue(charge.Success, "Charge must succeed first");

        var refund = await _gateway.RefundAsync(charge.ChargeId);

        Assert.IsTrue(refund.Success);
        Assert.IsFalse(string.IsNullOrEmpty(refund.RefundId));
    }

    [TestMethod]
    public async Task DoubleRefund_SecondFails()
    {
        var charge = await _gateway.ChargeAsync("tok_valid_visa", 30m);
        Assert.IsTrue(charge.Success);

        var first = await _gateway.RefundAsync(charge.ChargeId);
        Assert.IsTrue(first.Success);

        var second = await _gateway.RefundAsync(charge.ChargeId);
        Assert.IsFalse(second.Success, "Duplicate refund should fail");
    }
}

